import React, { Fragment, useCallback, useEffect, useRef, useState } from 'react';
import { connect } from 'react-redux';
import 'react-tabs/style/react-tabs.css';
import Form from 'react-validation/build/form';
import { setAuthenticatedUser } from '../../../reduxStore/actions/authActions';
import { setCompanyData } from '../../../reduxStore/actions/flowActions';
import { tutorialModalOpen } from '../../../reduxStore/actions/modalsActions';
import cls from './BillingInfo.module.scss';
import { Button, ModalR, RenderTitle } from '../../common';
import { first } from 'rxjs/operators';
import { getCompanyDetails } from '../../../services/company.service';
import { loadStripe } from '@stripe/stripe-js';
import { now } from 'moment';
import { rightUp } from '../../../assets/images/icons';
import { dropdownOrderIcon, dropdownOrderUpIcon, tickCercle } from '../../../assets/images/new-icons';
import { getInvoices, getStripePlans, getCurrentSubscription, unsubscribe } from '../../../services/payments.service';
import { useTable } from 'react-table';
import { useNavigate } from 'react-router-dom';
import moment from 'moment';
import HeaderTopBar from '../../common/HeaderTopBar/HeaderTopBar';
import CancelMembership from './CancelMembership';
import MessageContainer from '../ProcessesComps/MessageContainer/MessageContainer';

let stripePromise;

const getStripe = () => {
	if (!stripePromise) {
		stripePromise = loadStripe(process.env.REACT_APP_STRIPE_PUBLIC_KEY);
	}

	return stripePromise;
};

function BillingInfo(props) {
	const [stripeError, setStripeError] = useState(null);
	const { companyData, onSetCompanyDataField } = props;
	const form = useRef();
	const [apiError, setApiError] = useState('');
	const [products, setProducts] = useState([]);
	const [prices, setPrices] = useState([]);
	const [loading, setLoading] = useState(false);
	const [invoices, setInvoices] = useState([]);
	const [subscriptionInfo, setSubscriptionInfo] = useState({
		end_date: '',
	});
	const [servicesPurchased, setServicesPurchased] = useState([]);
	const [latestDatePurchased, setLatestDatePurchased] = useState(null);
	const [showCancelMembership, setShowCancelMembership] = useState(false);

	const { name } = companyData;
	const [fieldsErrors] = useState({
		name: '',
		founding_date: '',
		employees_no: '',
		industry: '',
		description: '',
		position: '',
		misc_info: '',
	});
	const [, setElementsTouched] = useState({
		name: false,
		founding_date: false,
		employees_no: false,
		industry: false,
		description: false,
		position: false,
	});

	const nameChangeHandler = e => {
		onSetCompanyDataField({ name: e.target.value });
	};
	const industryChangeHandler = e => {
		onSetCompanyDataField({ industry: e.target.value });
	};

	const retrivePaymentPlansAndSubscriptions = () =>
		getStripePlans()
			.pipe(first())
			.subscribe({
				next: data => {
					setProducts(data.product);
					setPrices(data.prices);
					const defaultPriceForSubscription = data?.product?.find(pr => pr.name === 'FlowHero User Subscription');
					if (defaultPriceForSubscription) {
						let newSubscriptionMetaData = [];
						Object.entries(defaultPriceForSubscription.metadata).map(item => {
							item[1] = JSON.parse(item[1]);
							newSubscriptionMetaData.push(item);
						});
						newSubscriptionMetaData = Object.fromEntries(newSubscriptionMetaData);
						getCurrentSubscription()
							.pipe(first())
							.subscribe({
								next: data => {
									setServicesPurchased(data.services);
									if (data.services != undefined) {
										if (data.services.length > 0) {
											const date_temp = new Date(
												Math.max(
													...data.services.map(element => {
														return new Date(element.ends_at);
													})
												)
											);
											if (date_temp > now()) {
												setLatestDatePurchased(date_temp);
											}
										}
									}

									if (data.subscription !== undefined) {
										const startDate = new Date(data.subscription.start_date);
										const endDate = new Date(startDate.setMonth(startDate.getMonth() + 1));
										const count = companyData.billable_users ?? 0;
										Object.entries(newSubscriptionMetaData).map(item => {
											if (count <= item[1].max && count >= item[1].min) {
												var formatter = new Intl.NumberFormat('en-US', {
													style: 'currency',
													currency: item[1].currency,
												});
												setSubscriptionInfo({
													...data.subscription,
													end_date: endDate.toDateString(),
													plan: item[0],
													plan_price: `${item[1].currency} ${formatter.format(item[1].price)}`,
													price_code: defaultPriceForSubscription.default_price,
													total: `${item[1].currency} ${formatter.format(item[1].price * count)}`,
												});
												onSetCompanyDataField({ billing_info: data.billing_info });
											}
										});
									} else if (data.message === 'Company still on trial') {
										const count = companyData.billable_users ?? 0;
										Object.entries(newSubscriptionMetaData).map(item => {
											if (count <= item[1].max && count >= item[1].min) {
												var formatter = new Intl.NumberFormat('en-US', {
													style: 'currency',
													currency: item[1].currency,
												});
												setSubscriptionInfo({
													plan: item[0],
													plan_price: `${item[1].currency} ${formatter.format(item[1].price)}`,
													price_code: defaultPriceForSubscription.default_price,
													total: `${item[1].currency} ${formatter.format(item[1].price * count)}`,
												});
											}
										});
									}
								},
								error: () => {},
							});
					}
				},
				error: () => {},
			});

	const parseInvoices = useCallback(invoices => {
		const parsedInvoices = [];

		if (invoices?.length === 0) return;
		invoices.map(elem => {
			return parsedInvoices.push({
				description: elem.description,
				total: elem?.invoice_total,
				status: elem.status,
				date: moment(elem.invoice_date).format('MMMM Do, YYYY'),
				url: (
					<a href={elem.invoice_url} target="_blank" rel="noreferrer">
						View Invoice
					</a>
				),
			});
		});
		setInvoices(parsedInvoices);
	}, []);

	const retriveInvoices = () =>
		getInvoices()
			.pipe(first())
			.subscribe({
				next: data => {
					data.invoices && parseInvoices(data.invoices);
				},
				error: () => {},
			});

	useEffect(() => {
		retrivePaymentPlansAndSubscriptions();
		retriveInvoices();
	}, []);

	const payServices = (service_name, price) => {
		navigate('/checkout', {
			state: {
				service_name: service_name,
				price: price,
			},
		});
	};
	const redirectToCheckout = async ({ price }) => {
		const item = {
			price: price,
			quantity: 1,
		};

		const checkoutOptions = {
			lineItems: [item],
			mode: 'payment',
			billingAddressCollection: 'required',
			customerEmail: companyData.billing_info.email,
			clientReferenceId: companyData.billing_info.id,
			successUrl: `${window.location.origin}/success`,
			cancelUrl: `${window.location.origin}/cancel`,
		};
		const stripe = await getStripe();

		setLoading(true);

		const { error } = await stripe.redirectToCheckout(checkoutOptions);

		if (error) setStripeError(error.message);
		setLoading(false);
	};

	const renderPlanSubscriptions = (subs, name) => {
		return (
			Object.keys(subs).length > 0 &&
			Object.keys(subs).map((type, index) => {
				const subsJ = JSON.parse(subs[type]);
				const disabled = servicesPurchased.length == 0 ? false : servicesPurchased.filter(sp => new Date(sp.ends_at).getTime() > now() && sp.stripe_price === subsJ.price_code && sp.stripe_product === name).length > 0;
				return (
					// eslint-disable-next-line react/jsx-key
					<Button disabled={disabled} key={index} className={cls.planButton} lighter style={{ marginBottom: '4px' }} loading={loading} title={type === 'Basic' ? 'Purchase Now' : `Subscribe for ` + type} clicked={() => payServices(name, subsJ)} />
				);
			})
		);
	};

	const columns = React.useMemo(
		() => [
			{
				Header: () => {
					return (
						<span>
							<img style={{ marginRight: '6px', marginBottom: '-2px', color: 'white' }} alt={''} />
							Invoice Date
						</span>
					);
				},
				accessor: 'date',
			},
			{
				Header: () => {
					return (
						<span>
							<img style={{ marginRight: '6px', marginBottom: '-2px' }} alt={''} />
							Description
						</span>
					);
				},
				accessor: 'description',
			},
			{
				Header: () => {
					return (
						<span>
							<img style={{ marginRight: '6px', marginBottom: '-2px' }} alt={''} />
							Invoice Total
						</span>
					);
				},
				accessor: 'total',
			},
			{
				Header: () => {
					return (
						<span>
							<img style={{ marginRight: '6px', marginBottom: '-2px' }} alt={''} />
							Status
						</span>
					);
				},
				accessor: 'status',
			},
			{
				Header: () => {
					return (
						<span>
							<img style={{ marginRight: '6px', marginBottom: '-2px' }} alt={''} />
							Invoice
						</span>
					);
				},
				accessor: 'url',
			},
		],
		[]
	);

	const renderInvoices = () => {
		return (
			<Fragment>
				<Table columns={columns} data={invoices} />
				{invoices.length === 0 && <p className={cls.noPaymentInfo}>{'No available invoices.'}</p>}
			</Fragment>
		);
	};

	const renderPlans = () => {
		return (
			products.length > 0 &&
			products.slice(0, 2).map((product, idx) => {
				const price = prices.find(p => p.id === product.default_price) ?? { cost: '0.00', currency: '' };
				return (
					<div key={idx} className={cls.additionalPlanContainer} style={{ marginRight: '20px' }}>
						<p className={cls.planTitle}>{product.name}</p>
						<p className={cls.planPrice}>
							{price.currency.toUpperCase()} {price.cost} <span className={cls.month}>/month</span>
						</p>
						<div className={cls.planDescriptionContainer}>
							<img alt={''} src={tickCercle} />
							<p className={cls.planDescription} style={{ fontSize: '16px' }}>
								{product.description}
							</p>
						</div>
						{Object.keys(product.metadata).length > 0
							? companyData.status === 'active' && renderPlanSubscriptions(product.metadata, product.id)
							: companyData.status === 'active' && <Button loading={loading} lighter className={cls.planButton} clicked={() => redirectToCheckout({ price: product.default_price })} title={'Purchase Now'} />}
						<br />
					</div>
				);
			})
		);
	};

	const navigate = useNavigate();
	return (
		<div className={cls.billingInfoHost}>
			<p className={cls.sectionTitle} style={{ marginTop: '80px', display: companyData.pm_last_four ? '' : '' }}>
				Payment Information
			</p>
			<div className={cls.formWrapper} style={{ display: companyData.pm_last_four ? '' : '' }}>
				<Form ref={form} className={form}>
					<div style={{ width: '600px' }}>
						<RenderTitle title={'Payment Method'} />
						<input
							disabled
							type="text"
							name="paymentmet"
							className={cls.inputField}
							value={companyData.pm_last_four ? `**********${companyData.pm_last_four}` : ''}
							onChange={nameChangeHandler}
							onFocus={() => {
								setElementsTouched(c => ({ ...c, name: true }));
							}}
						/>
					</div>
					<div className={cls.containerWrapper}>
						<div className={cls.inputWrapper}>
							<RenderTitle title={'Billing Email Address'} />
							<input
								disabled
								type="text"
								className={cls.inputField}
								// placeholder="Type here..."
								value={companyData.billing_info.email ?? ''}
								onChange={nameChangeHandler}
								onFocus={() => {
									setElementsTouched(c => ({ ...c, name: true }));
								}}
							/>
						</div>
						{/* <div className={cls.inputWrapper}>
							<RenderTitle title={'VAT Number (if applicable)'} tooltipText={'In case you need to attach a VAT number to invoices.'} />
							<input
								disabled
								type="text"
								name="vatnum"
								className={cls.inputField}
								// placeholder="Type here..."
								value={name ?? ''}
								onChange={nameChangeHandler}
								onFocus={() => {
									setElementsTouched(c => ({ ...c, name: true }));
								}}
							/>
						</div> */}
					</div>
					<div style={{ paddingTop: '15px' }}>
						<RenderTitle title={'Billing Physical Address'} tooltipText={'One of the organization’s official registered locations.'} />
						<input
							disabled
							type="text"
							name="billadd"
							className={cls.inputField}
							// placeholder="Type here..."
							value={`${companyData.billing_info.line1 ?? ''} ${companyData.billing_info.city ?? ''} ${companyData.billing_info.state ?? ''} ${companyData.billing_info.postal_code ?? ''} ${companyData.billing_info.country ?? ''}` ?? ''}
							onChange={industryChangeHandler}
							onFocus={() => {
								setElementsTouched(c => ({ ...c, industry: true }));
							}}
						/>
					</div>
					<div style={{ paddingTop: '15px', display: 'none' }}>
						<Button className={cls.updateButton} title={companyData.pm_last_four ? 'Update Payment Information' : 'Save Payment Information'} clicked={() => setApiError('Coming soon.')} />
					</div>
				</Form>
				<div>
					{Object.entries(fieldsErrors).map(([key, value]) =>
						value?.length > 0 ? (
							<p key={key} className={cls.errorParagraph}>
								{value}
							</p>
						) : null
					)}
				</div>
			</div>
			{apiError?.length > 0 && <p className={cls.errorParagraph}>{apiError}</p>}
			{(companyData.status === 'on_trial' || companyData.status === 'trial_ended' || subscriptionInfo.price_code !== undefined) && (
				<div>
					<p className={cls.sectionTitle}>Invoices</p>
					<div className={cls.trialContainer}>
						<p className={cls.trialTitle}>Active plan</p>
						<div style={{ display: 'flex' }}>
							<p className={cls.trialText}>{companyData.status === 'trial_ended' ? 'Trial ended' : `Trial (${parseInt((new Date(companyData.trial_ends_at).getTime() - now()) / (1000 * 3600 * 24))} Days)`}</p>
							<Button
								//className={cls.trialButton}
								title={companyData.status === 'trial_ended' ? 'Subscribe' : 'Upgrade Plan'}
								//icon={<img src={dropdownOrderUpIcon} alt={''} />}
								clicked={() =>
									navigate('/checkout', {
										state: {
											companyData: companyData,
											subscriptionInfo: subscriptionInfo,
										},
									})
								}
							/>
						</div>
					</div>
				</div>
			)}
			{(subscriptionInfo.plan && companyData.status === 'inactive') ||
				(subscriptionInfo.price_code !== undefined && (
					<div>
						<div className={cls.trialContainer}>
							<p className={cls.trialTitle}>Active plan</p>
							<div style={{ display: 'flex' }}>
								<p className={cls.trialText}>{'Inactive'}</p>
								<Button
									className={cls.trialButton}
									title={'Resubscribe'}
									icon={<img src={dropdownOrderIcon} alt={''} />}
									clicked={() =>
										navigate('/checkout', {
											state: {
												companyData: companyData,
												subscriptionInfo: subscriptionInfo,
											},
										})
									}
								/>
							</div>
						</div>
					</div>
				))}

			{stripeError && <MessageContainer message={stripeError} />}
			{products.length > 0 && (
				<div
					style={{
						paddingTop: '50px',
						paddingBottom: '50px',
						display: companyData.status === 'active' ? '' : '',
					}}
				>
					<p className={cls.sectionTitle}>Additional Purchases</p>
					<div className={cls.plansContainer}>{renderPlans()}</div>
					<div style={{ width: '400px', display: 'flex', flexDirection: 'row' }}>
						<p className={cls.planDescription} style={{ paddingRight: '10px' }}>
							* Purchasing Business Consulting for 6 months will get you 50% off on your first Onboarding.
						</p>
						<p className={cls.planDescription}>** Purchasing Business Consulting for 1 year will get you your first Onboarding FREE.</p>
					</div>
				</div>
			)}

			{subscriptionInfo.plan ||
				(companyData.status === 'active' && subscriptionInfo.price_code !== undefined && (
					<Button
						className={cls.logoutButton}
						title={'Cancel Subscription'}
						clicked={() => {
							setShowCancelMembership(true);
						}}
					/>
				))}
			<br />
			{invoices && companyData.status !== 'on_trial' && companyData.status !== 'trial_ended' && (
				<>
					<p className={cls.sectionTitle}>Invoices</p>
					{!(companyData.status === 'on_trial' || companyData.status === 'trial_ended' || companyData.status === 'inactive') && (
						<div>
							<div className={cls.currentInvoicesContainer}>
								<p className={cls.trialTitle}>Next Invoice</p>
								<div style={{ display: 'flex' }}>
									<p className={cls.trialText}>{subscriptionInfo.end_date ?? '---'}</p>
								</div>
							</div>
							<div className={cls.currentInvoicesContainer}>
								<p className={cls.trialTitle}>Next Invoice Total</p>
								<div style={{ display: 'flex' }}>
									<p className={cls.trialText}>{subscriptionInfo.total ?? '0.00'}</p>
								</div>
							</div>
							<div className={cls.currentInvoicesContainer}>
								<p className={cls.trialTitle}>Active Plan</p>
								<div style={{ display: 'flex' }}>
									<p className={cls.trialText}>
										{subscriptionInfo.plan} ({companyData.users_count} members)
									</p>
								</div>
							</div>
							{latestDatePurchased && (
								<div className={cls.currentInvoicesContainer}>
									<p className={cls.trialTitle}>Additional Purchases until</p>
									<div style={{ display: 'flex' }}>
										<p className={cls.trialText}>{new Date(latestDatePurchased).toDateString()}</p>
									</div>
								</div>
							)}
						</div>
					)}
					{renderInvoices()}
				</>
			)}
			<br />
			{
				<ModalR
					blured={true}
					scrollable={true}
					isOpen={showCancelMembership}
					onClose={() => {
						setShowCancelMembership(false);
					}}
					backdropColor={true}
					shadowedContainerStyle={{ width: '680px' }}
				>
					<CancelMembership
						onCancelMembership={reasons => {
							setShowCancelMembership(false);
							unsubscribe(reasons)
								.pipe(first())
								.subscribe({
									next: () => {
										getCompanyDetails().pipe(first()).subscribe({});
									},
									error: error => {
										setStripeError(error.data.message.message);
									},
								});
						}}
						onClose={() => {
							setShowCancelMembership(false);
						}}
					/>
				</ModalR>
			}
		</div>
	);
}

function Table({ columns, data }) {
	// Use the state and functions returned from useTable to build your UI
	const { getTableProps, getTableBodyProps, headerGroups, rows, prepareRow } = useTable({
		columns,
		data,
	});

	// Render the UI for your table
	return (
		<div className={cls.tasksTableHost}>
			<table {...getTableProps()}>
				<thead>
					{headerGroups.map(headerGroup => (
						// eslint-disable-next-line react/jsx-key
						<tr {...headerGroup.getHeaderGroupProps()}>
							{headerGroup.headers.map(column => (
								// eslint-disable-next-line react/jsx-key
								<th {...column.getHeaderProps()}>{column.render('Header')}</th>
							))}
						</tr>
					))}
				</thead>
				<tbody {...getTableBodyProps()}>
					{rows.map(
						(row, index) =>
							prepareRow(row) || (
								<tr key={index} {...row.getRowProps()}>
									{row.cells.map(cell => {
										// eslint-disable-next-line react/jsx-key
										return <td {...cell.getCellProps()}>{cell.render('Cell')}</td>;
									})}
								</tr>
							)
					)}
				</tbody>
			</table>
		</div>
	);
}

const mapStateToProps = store => {
	const {
		authenticatedUser: { position },
	} = store.authReducer;
	const { companyData, companyPositionsArray, companyUsersArray } = store.flowReducer;
	return { companyData, companyPositionsArray, position, companyUsersArray };
};

const mapDispatchToProps = dispatch => {
	return {
		onSetCompanyDataField: field => dispatch(setCompanyData(field)),
		onSetAuthenticatedUserPosition: position => dispatch(setAuthenticatedUser(position)),
		onTutorialModalOpen: options => dispatch(tutorialModalOpen(options)),
	};
};
export default connect(mapStateToProps, mapDispatchToProps)(BillingInfo);
